// Extract FAQ query from message
const message = $json.message || '';

let query = message
  .replace(/syarat/gi, '')
  .replace(/ketentuan/gi, '')
  .replace(/prosedur/gi, '')
  .replace(/cara/gi, '')
  .replace(/bagaimana/gi, '')
  .replace(/aturan/gi, '')
  .trim();

if (!query || query.length < 2) {
  query = 'info';
}

return {
  json: {
    ...$json,
    query: query
  }
};

// Format FAQ response
const data = $json.data || {};
const query = $('Extract FAQ Query').item.json.query;

if (!data.question && !data.answer) {
  // No FAQ found, ask for complaint confirmation
  return {
    json: {
      phone: $('Extract FAQ Query').item.json.phone,
      chatId: $('Extract FAQ Query').item.json.chatId,
      reply: `❓ *INFORMASI BELUM TERSEDIA*\n\nMaaf, tidak ditemukan informasi untuk "${query}"\n\nApakah pesan ini ingin dijadikan pengaduan resmi?\n\n✅ Balas *YA* untuk membuat pengaduan\n❌ Balas *TIDAK* untuk membatalkan`,
      needsConfirmation: true,
      originalMessage: $('Extract FAQ Query').item.json.message
    }
  };
}

let replyText = `📋 *INFORMASI*\n\n`;
replyText += `❓ *${data.question || query}*\n\n`;
replyText += `${data.answer || 'Informasi tidak tersedia'}\n\n`;

if (data.requirements && data.requirements.length > 0) {
  replyText += `📄 *Syarat:*\n`;
  data.requirements.forEach((req, i) => {
    replyText += `${i + 1}. ${req}\n`;
  });
  replyText += `\n`;
}

if (data.steps && data.steps.length > 0) {
  replyText += `📝 *Langkah-langkah:*\n`;
  data.steps.forEach((step, i) => {
    replyText += `${i + 1}. ${step}\n`;
  });
  replyText += `\n`;
}

replyText += `💡 Ketik MENU untuk layanan lain`;

return {
  json: {
    phone: $('Extract FAQ Query').item.json.phone,
    chatId: $('Extract FAQ Query').item.json.chatId,
    reply: replyText,
    needsConfirmation: false
  }
};

// Error response
const query = $('Extract FAQ Query').item.json.query;

const replyText = `❌ *ERROR*\n\nGagal mencari informasi. Silakan coba lagi nanti.\n\n💡 Ketik MENU untuk melihat daftar layanan.`;

return {
  json: {
    phone: $('Extract FAQ Query').item.json.phone,
    chatId: $('Extract FAQ Query').item.json.chatId,
    reply: replyText,
    needsConfirmation: false
  }
};
